$private=getenv('PRIVATE_DIR')?:dirname(__DIR__,2).'/private';$db=ResearchDb::open($private);$msg='';$err='';
try {
 if($_SERVER['REQUEST_METHOD']==='POST' && isset($_FILES['firmware'])){
   $id=(new FirmwareImporter($db,$private))->import($_FILES['firmware']['tmp_name'],$_FILES['firmware']['name'],trim($_POST['notes']??''));
   $project=FirmwareParameterExtractor::projectData($db,$id,(string)($_POST['printer_model']??'auto'),trim((string)($_POST['project_name']??'')));
   $project['profile_id']=0;
   $profileId=PrinterProfiles::save($db,$project);
   $msg="Imported package #$id and created research project #$profileId";
   $_GET['profile']=$profileId;
 }
 if($_SERVER['REQUEST_METHOD']==='POST' && ($_POST['action']??'')==='export_project'){
   $path=ProjectExporter::export($db,(int)($_POST['profile_id']??0),$private);
   header('Content-Type: application/json');header('Content-Disposition: attachment; filename="'.basename($path).'"');readfile($path);exit;
 }
 if($_SERVER['REQUEST_METHOD']==='POST' && ($_POST['action']??'')==='download_official'){
   $pid=(int)($_POST['package_id']??0);$q=$db->prepare('SELECT original_name,stored_name FROM firmware_packages WHERE id=?');$q->execute([$pid]);$pkg=$q->fetch(PDO::FETCH_ASSOC);if(!$pkg)throw new RuntimeException('Firmware package not found');
   $path=rtrim($private,'/').'/bambu/firmware/'.$pkg['stored_name'];if(!is_file($path))throw new RuntimeException('Archived OTA file missing');
   header('Content-Type: application/zip');header('Content-Disposition: attachment; filename="'.basename($pkg['original_name']).'"');readfile($path);exit;
 }
 if($_SERVER['REQUEST_METHOD']==='POST' && ($_POST['action']??'')==='refill_profile'){
   $profileId=(int)($_POST['profile_id']??0);
   $model=(string)($_POST['refill_model']??'auto');
   $overwrite=($_POST['overwrite_known']??'0')==='1';
   $id=FirmwareParameterExtractor::refillProfile($db,$profileId,$model,$overwrite);
   $msg=$overwrite?'Re-extracted and refreshed project parameters':'Auto-filled blank project parameters';
   $_GET['profile']=$id;
 }
 if($_SERVER['REQUEST_METHOD']==='POST' && ($_POST['action']??'')==='generate_stock_probe'){
   $path=StockFirmwareBuilder::generate($db,(int)($_POST['profile_id']??0),$_POST,$private);
   header('Content-Type: application/zip');header('Content-Disposition: attachment; filename="'.basename($path).'"');readfile($path);exit;
 }
 if($_SERVER['REQUEST_METHOD']==='POST' && ($_POST['action']??'')==='save_profile'){
   if(($_POST['save_mode']??'update')==='copy') $_POST['profile_id']=0;
   $id=PrinterProfiles::save($db,$_POST);$msg="Saved Bambu research project #$id";$_GET['profile']=$id;
 }
} catch(Throwable $e){$err=$e->getMessage();}
$packages=$db->query('SELECT p.*,(SELECT COUNT(*) FROM firmware_components c WHERE c.package_id=p.id) component_count FROM firmware_packages p ORDER BY imported_at DESC')->fetchAll(PDO::FETCH_ASSOC);
$boards=$db->query('SELECT * FROM boards ORDER BY printer_code,board_role,board_revision')->fetchAll(PDO::FETCH_ASSOC);
$hardware=$db->query('SELECT * FROM hardware_components ORDER BY printer_code,board_role,component_role')->fetchAll(PDO::FETCH_ASSOC);
$connectors=$db->query('SELECT * FROM board_connectors ORDER BY printer_code,board_role,connector_name')->fetchAll(PDO::FETCH_ASSOC);
$profiles=PrinterProfiles::list($db);$profileId=(int)($_GET['profile']??0);$profile=$profileId?PrinterProfiles::get($db,$profileId):null;
if(!$profile){$profile=array_merge(['id'=>0,'printer_code'=>'','profile_name'=>''],PrinterProfiles::DEFAULTS);}
$evidence=$profile['id']?PrinterProfiles::evidence($db,(int)$profile['id']):[];
$readiness=PrinterProfiles::readiness($db,$profile);$stockStatus=StockFirmwareBuilder::status($db,$profile);
$compare=[];$aid=(int)($_GET['a']??0);$bid=(int)($_GET['b']??0);if($aid&&$bid&&$aid!==$bid)$compare=FirmwareCompare::run($db,$aid,$bid);
function h($s){return htmlspecialchars((string)$s,ENT_QUOTES,'UTF-8');}
function val($p,$k){return h($p[$k]??'');} function checked($p,$k){return !empty($p[$k])?'checked':'';}
function num($p,$k,$min='',$max='',$step='any'){echo '<input type="number" name="'.h($k).'" value="'.val($p,$k).'"'.($min!==''?' min="'.$min.'"':'').($max!==''?' max="'.$max.'"':'').' step="'.$step.'">';}
