] as $group=>$keys):$known=0;foreach($keys as $key)if(($profile[$key]??'')!==''&&($profile[$key]??null)!==null)$known++;?><div class="extract-card"><strong><?=h($group)?></strong><span><?=$known?> / <?=count($keys)?> populated</span><small><?= $known===count($keys)?'Available':'Unknown fields remain blank' ?></small></div><?php endforeach;?></div></section>
